468→                state.on_stack.remove(w);
469→                component.push(w.to_string());
470→                if w == node {
471→                    break;
472→                }
473→            }
474→            component.sort(); // Deterministic ordering within SCC
475→            state.result.push(component);
476→        }
477→    }
